## 3.  `pcapng_stubs.cpp` – the C/C++ glue code

> **Important** – compile this file with a C++ compiler (`g++`, `clang++`,
> …) and **link it as a C object** (`-c -fPIC`).  The `extern "C"` blocks
> expose the symbols with C linkage so that the OCaml runtime can find
> them.

```cpp
/*=====================================================================
  pcapng_stubs.cpp – OCaml <-> libpcapng glue
  =====================================================================*/

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <cstring>   // memcpy
#include <string>
#include <memory>

/* ------------------------------------------------------------------
   libpcapng – the (fictional) C++ API we are binding to.
   ------------------------------------------------------------------ */

/* The real libpcapng library provides a `FileReader` class that can be
   iterated with a standard C++ iterator.  For the purpose of this
   binding we only need a tiny façade that can:

   * open a file,
   * ask for the next frame,
   * release resources.

   The following mock‑up mimics the real API closely enough to compile
   and to serve as a reference for the actual library you will link
   against.  Replace the implementation with the real one when you
   integrate.                                            */

namespace pcapng {

/* A raw packet as returned by libpcapng.  All fields are public for
   simplicity.  In the real library they may be accessed via getters. */
struct Frame {
  uint64_t timestamp_ns;          // nanoseconds since epoch
  uint32_t captured_len;          // bytes stored in file
  uint32_t original_len;          // length on the wire
  const uint8_t* data;            // pointer into the file‑mapped buffer
};

/* A very small reader that memory‑maps the file and walks a vector of
   frames.  The real library does something more sophisticated. */
class FileReader {
public:
  explicit FileReader(const std::string& path) {
    // ---- MOCK IMPLEMENTATION -------------------------------------------------
    // In real code you would open the file, parse the Section Header Block,
    // and build an iterator over Interface Description Blocks / Enhanced
    // Packet Blocks, etc.
    // -------------------------------------------------------------------------
    (void)path; // silence unused‑parameter warning
    // For demonstration we pretend the file contains exactly three frames.
    static const uint8_t dummy0[] = {0xde,0xad,0xbe,0xef};
    static const uint8_t dummy1[] = {0xca,0xfe,0xba,0xbe};
    static const uint8_t dummy2[] = {0x00,0x11,0x22,0x33,0x44};

    frames_.push_back({ 1620000000000000000ULL, 4, 4, dummy0 });
    frames_.push_back({ 1620000001000000000ULL, 4, 4, dummy1 });
    frames_.push_back({ 1620000002000000000ULL, 5, 5, dummy2 });
    // -------------------------------------------------------------------------
  }

  using iterator = std::vector<Frame>::const_iterator;
  iterator begin() const { return frames_.cbegin(); }
  iterator end()   const { return frames_.cend(); }

private:
  std::vector<Frame> frames_;
};

} // namespace pcapng

/* ------------------------------------------------------------------
   OCaml custom block that holds a pointer to the C++ reader.
   ------------------------------------------------------------------ */

typedef struct {
  std::unique_ptr<pcapng::FileReader> *reader;   // heap‑allocated unique_ptr
} caml_pcapng;

/* Finalizer – called when the OCaml value is GC‑collected */
static void caml_pcapng_finalize(value v) {
  caml_pcapng *c = (caml_pcapng *)Data_custom_val(v);
  delete c->reader;               // destroys the unique_ptr → frees the reader
  c->reader = nullptr;
}

/* Custom operations table */
static struct custom_operations caml_pcapng_ops = {
  "org.example.pcapng",
  caml_pcapng_finalize,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default
};

/* ------------------------------------------------------------------
   Helper: allocate a fresh OCaml custom block wrapping a new FileReader.
   ------------------------------------------------------------------ */
static value caml_pcapng_wrap_reader(std::unique_ptr<pcapng::FileReader> &&r) {
  CAMLparam0();
  CAMLlocal1(v);
  v = caml_alloc_custom(&caml_pcapng_ops, sizeof(caml_pcapng), 0, 1);
  caml_pcapng *c = (caml_pcapng *)Data_custom_val(v);
  c->reader = new std::unique_ptr<pcapng::FileReader>(std::move(r));
  CAMLreturn(v);
}

/* ------------------------------------------------------------------
   Convert a libpcapng::Frame into an OCaml record of type `frame`.
   ------------------------------------------------------------------ */
static value caml_frame_of_pcapng(const pcapng::Frame &f) {
  CAMLparam0();
  CAMLlocal4(ocaml_frame, ts, caplen, origlen, data);

  /* 0 – timestamp (int64) */
  ts = caml_copy_int64((int64_t)f.timestamp_ns);

  /* 1 – captured_len (int) */
  caplen = Val_int((int)f.captured_len);

  /* 2 – original_len (int) */
  origlen = Val_int((int)f.original_len);

  /* 3 – data (bytes) */
  data = caml_alloc_string((mlsize_t)f.captured_len);
  memcpy(String_val(data), f.data, (size_t)f.captured_len);

  /* Build the record */
  ocaml_frame = caml_alloc(4, 0);          // 4 fields, tag = 0 (only one constructor)
  Store_field(ocaml_frame, 0, ts);
  Store_field(ocaml_frame, 1, caplen);
  Store_field(ocaml_frame, 2, origlen);
  Store_field(ocaml_frame, 3, data);

  CAMLreturn(ocaml_frame);
}

/* ------------------------------------------------------------------
   External primitives – these are the symbols visible to OCaml.
   ------------------------------------------------------------------ */

extern "C" {

/*--------------------------------------------------------------
   val open_file : string -> t
   --------------------------------------------------------------*/
CAMLprim value pcapng_open_file(value v_path) {
  CAMLparam1(v_path);
  CAMLlocal1(v_res);
  const char *path = String_val(v_path);
  try {
    auto reader = std::make_unique<pcapng::FileReader>(std::string(path));
    v_res = caml_pcapng_wrap_reader(std::move(reader));
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  } catch (...) {
    caml_failwith("pcapng_open_file: unknown error");
  }
  CAMLreturn(v_res);
}

/*--------------------------------------------------------------
   val close : t -> unit
   --------------------------------------------------------------*/
CAMLprim value pcapng_close(value v_handle) {
  CAMLparam1(v_handle);
  /* The custom block’s finalizer will run automatically when the value
     becomes unreachable.  We simply force the finalizer now, which also
     clears the pointer so that further use raises a clear error. */
  caml_pcapng_finalize(v_handle);
  CAMLreturn(Val_unit);
}

/*--------------------------------------------------------------
   val iter : t -> (frame -> unit) -> unit
   --------------------------------------------------------------*/
CAMLprim value pcapng_iter(value v_handle, value v_cb) {
  CAMLparam2(v_handle, v_cb);
  caml_pcapng *c = (caml_pcapng *)Data_custom_val(v_handle);
  if (!c->reader || !(c->reader->get())) caml_failwith("pcapng_iter: invalid handle");

  const pcapng::FileReader &reader = *(c->reader->get());
  for (auto it = reader.begin(); it != reader.end(); ++it) {
    value ocaml_frame = caml_frame_of_pcapng(*it);
    // Call the OCaml callback.  Use `caml_callback_exn` to catch exceptions.
    value res = caml_callback_exn(v_cb, ocaml_frame);
    if (Is_exception_result(res)) {
      // Propagate the OCaml exception to the caller.
      caml_raise(res);
    }
    // The callback returns unit, we ignore the result.
  }
  CAMLreturn(Val_unit);
}

/*--------------------------------------------------------------
   val iter_until : t -> (frame -> bool) -> bool
   --------------------------------------------------------------*/
CAMLprim value pcapng_iter_until(value v_handle, value v_cb) {
  CAMLparam2(v_handle, v_cb);
  CAMLlocal1(res);
  caml_pcapng *c = (caml_pcapng *)Data_custom_val(v_handle);
  if (!c->reader || !(c->reader->get())) caml_failwith("pcapng_iter_until: invalid handle");

  const pcapng::FileReader &reader = *(c->reader->get());
  bool stopped_early = false;

  for (auto it = reader.begin(); it != reader.end(); ++it) {
    value ocaml_frame = caml_frame_of_pcapng(*it);
    // The callback returns a bool.  `true` → continue, `false` → stop.
    value cb_res = caml_callback_exn(v_cb, ocaml_frame);
    if (Is_exception_result(cb_res)) {
      caml_raise(cb_res);          // propagate exception
    }
    if (cb_res == Val_false) {     // user asked to stop early
      stopped_early = true;
      break;
    }
  }
  // Return true if we *did not* stop early (i.e. fully traversed).
  res = stopped_early ? Val_false : Val_true;
  CAMLreturn(res);
}

} // extern "C"
```

